import { Component, OnInit } from '@angular/core';
import { WeatherService } from '../../../../core/services/weather.service';
import { ExportService } from '../../../../core/services/export.service';
import { HistoricoConsulta } from '../../../../core/models/models';
import { I18nService } from '../../../../core/services/theme-i18n.service';

@Component({
  selector: 'app-history-table',
  templateUrl: './history-table.component.html',
  styleUrls: ['./history-table.component.scss'],
})
export class HistoryTableComponent implements OnInit {
  history: HistoricoConsulta[] = [];
  loading    = false;
  error      = '';
  successMsg = '';
  filterText = '';

  constructor(
    private weatherSvc: WeatherService,
    private exportSvc: ExportService,
    public  i18n: I18nService,
  ) {}

  ngOnInit(): void { this.load(); }

  load(): void {
    this.loading = true;
    this.weatherSvc.getHistorico().subscribe({
      next:  (r) => { this.history = r.data ?? []; this.loading = false; },
      error: ()  => this.loading = false,
    });
  }

  clear(): void {
    if (!confirm('Apagar todo o histórico?')) return;
    this.weatherSvc.limparHistorico().subscribe({
      next: () => { this.history = []; this.successMsg = 'Histórico eliminado.'; },
      error: (e) => this.error = e.error?.message,
    });
  }

  exportCSV(): void { this.exportSvc.exportHistoricoCSV(this.filteredHistory); }
  exportPDF(): void { this.exportSvc.exportHistoricoPDF(this.filteredHistory, ''); }

  get filteredHistory(): HistoricoConsulta[] {
    const q = this.filterText.toLowerCase();
    return q
      ? this.history.filter(h => h.cidade_consultada.toLowerCase().includes(q))
      : this.history;
  }
}
<div class="page-container">
  <div class="page-header">
    <h1>{{ 'history.title' | translate }}</h1>
    <div class="page-actions">
      <app-export-panel
        (exportCSV)="exportCSV()"
        (exportPDF)="exportPDF()"
      ></app-export-panel>
      <button class="btn btn-danger" (click)="clear()" [disabled]="!history.length">
        🗑️ {{ 'history.clear' | translate }}
      </button>
    </div>
  </div>

  <app-alert [message]="error"      type="error"   (dismiss)="error=''"></app-alert>
  <app-alert [message]="successMsg" type="success" (dismiss)="successMsg=''"></app-alert>

  <div class="table-toolbar">
    <input
      type="text"
      [(ngModel)]="filterText"
      [placeholder]="'common.search' | translate"
      class="table-search"
    />
    <span class="record-count">{{ filteredHistory.length }} registos</span>
  </div>

  <app-loading-spinner [loading]="loading" [label]="'common.loading' | translate"></app-loading-spinner>

  <div class="table-wrapper" *ngIf="!loading">
    <table class="data-table" *ngIf="filteredHistory.length; else empty">
      <thead>
        <tr>
          <th>{{ 'history.city' | translate }}</th>
          <th>{{ 'history.temp' | translate }}</th>
          <th>{{ 'history.climate' | translate }}</th>
          <th>{{ 'history.date' | translate }}</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let h of filteredHistory">
          <td><strong>{{ h.cidade_consultada }}</strong></td>
          <td><span class="temp-badge">{{ h.temperatura | number:'1.1-1' }}°C</span></td>
          <td>{{ h.clima | titlecase }}</td>
          <td class="date-cell">{{ h.data_consulta | date:'dd/MM/yyyy HH:mm' }}</td>
        </tr>
      </tbody>
    </table>
    <ng-template #empty>
      <div class="empty-state">
        <div class="empty-icon">📋</div>
        <p>{{ 'common.noData' | translate }}</p>
      </div>
    </ng-template>
  </div>
</div>
